import pytest

UTC_TIMESTAMP = "2024-06-01T09:30:00Z"
EXPECTED_UTC_TIME = "09:30"

@pytest.fixture
def no_tz_user_session(<auth_fixture>):
    return <auth_fixture>.login_with_tz(None)

def test_timestamp_defaults_to_utc_when_timezone_missing(
    no_tz_user_session, <page_fixture>
):
    resource_id = <seed_utc_timestamp>(UTC_TIMESTAMP)
    page = <page_fixture>(no_tz_user_session)
    page.goto(f"/resources/{resource_id}")

    rendered = page.locator("[data-testid='timestamp']").inner_text()

    assert EXPECTED_UTC_TIME in rendered, (
        f"Expected UTC fallback time {EXPECTED_UTC_TIME} in '{rendered}'"
    )
    assert page.locator("[data-testid='timestamp']").is_visible()

    <cleanup_resource>(resource_id)
